import{_ as i,o as e,c as a,ai as n}from"./chunks/framework.LxKgHzno.js";const c=JSON.parse('{"title":"AWS Bedrock","description":"","frontmatter":{},"headers":[],"relativePath":"providers/bedrock.md","filePath":"providers/bedrock.md","rawMarkdown":"# AWS Bedrock\\n\\n**Provider value:** `bedrock`\\n\\n## Setup\\n\\n**Option 1: AWS credential chain** (recommended)\\n\\nra uses the standard AWS credential chain:\\n\\n1. `AWS_ACCESS_KEY_ID` / `AWS_SECRET_ACCESS_KEY` env vars\\n2. `~/.aws/credentials` file\\n3. IAM instance roles\\n\\n```bash\\nexport AWS_ACCESS_KEY_ID=...\\nexport AWS_SECRET_ACCESS_KEY=...\\nexport AWS_REGION=us-east-1\\nra --provider bedrock \\"Hello\\"\\n```\\n\\n**Option 2: Bearer token**\\n\\nA bearer token can be set in a config file:\\n\\n```yaml\\napp:\\n  providers:\\n    bedrock:\\n      apiKey: your-bearer-token\\n```\\n\\n```bash\\nexport AWS_REGION=us-east-1\\nra --provider bedrock \\"Hello\\"\\n```\\n\\n## Environment variables\\n\\n| Variable | Required | Description |\\n|----------|----------|-------------|\\n| `AWS_REGION` | Yes | AWS region (e.g. `us-east-1`) |\\n\\n## Models\\n\\nUse the full Bedrock model ID:\\n\\n```bash\\nra --provider bedrock --model anthropic.claude-sonnet-4-6 \\"Triage this bug\\"\\n```\\n\\n## Extended thinking\\n\\nSupported modes: `off`, `low`, `medium`, `high`, `adaptive`.\\n\\n```bash\\nra --provider bedrock --thinking medium \\"Analyze this architecture\\"\\n```\\n\\n## See also\\n\\n- [Context Control](/core/context-control) — extended thinking details\\n- [Configuration](/configuration/) — provider credentials reference\\n"}'),t={name:"providers/bedrock.md"};function r(l,s,h,o,d,p){return e(),a("div",null,[...s[0]||(s[0]=[n("",21)])])}const g=i(t,[["render",r]]);export{c as __pageData,g as default};
